  gap: clamp(8px, 1.2cqw, 12px);
  min-width: 0;
}

.nb-ring {
  width: min(100%, clamp(132px, 15cqw, 178px));

  aspect-ratio: 1;

  margin: 0 auto;

  border-radius: 50%;

  display: grid;
  place-items: center;

  position: relative;

  background:
