(function () {
  const CONFIG = {
    max_items: 100,
    storage_key: "neo_batteries_hidden_entities_v1"
  };

  const mount = (typeof root !== "undefined" && root) ? root : document;
  const card = mount.querySelector("[data-neo-batteries]");

  if (!card) {
    console.error("Battery card not found");
    return;
  }

  let liveHass = (typeof hass !== "undefined") ? hass : window.hass || null;
  let filterMode = localStorage.getItem("neo_batteries_filter_v1") || "all";


  let lastDesignSurface = "";

  function cardHost() {
    try {
      if (typeof host !== "undefined" && host) return host;
    } catch (e) {}
    return null;
  }

  function getCardWrapper() {
    const h = cardHost();
    return h?.closest?.(".card-wrapper") || h?.parentElement?.closest?.(".card-wrapper") || card?.closest?.(".card-wrapper") || null;
  }

  function isTransparentCssValue(value) {
    const clean = String(value || "").trim().toLowerCase();
    if (!clean) return true;
    if (clean === "none" || clean === "transparent") return true;

    const compact = clean.replaceAll(" ", "");
    if (compact === "rgba(0,0,0,0)") return true;
    if (compact.startsWith("rgba(") && compact.endsWith(",0)")) return true;
    if (compact.startsWith("rgba(") && compact.endsWith(",0.0)")) return true;
    if (compact.startsWith("rgb(") && (compact.includes("/0)") || compact.includes("/0%)") || compact.includes("/0.0)") || compact.includes("/0.0%)"))) return true;
    return false;
  }

  function firstSurfaceValue(values) {
    for (const value of values) {
      const clean = String(value || "").trim();
      if (!isTransparentCssValue(clean)) return clean;
    }
    return "";
  }

  function wrapperCardStyle(wrapper) {
    if (!wrapper) return {};

    const raw = wrapper.dataset?.cardStyle || wrapper.getAttribute?.("data-card-style") || "";
    if (!raw) return {};

    try {
      const parsed = JSON.parse(raw);
      return parsed && typeof parsed === "object" ? parsed : {};
    } catch (e) {
      return {};
    }
  }

  function readDesignSurface() {
    const wrapper = getCardWrapper();
    const style = wrapperCardStyle(wrapper);

    const configured = firstSurfaceValue([
      style.background,
      style.container_background,
      style.card_background
    ]);
    if (configured) return configured;

    try {
      const h = cardHost();
      const styles = getComputedStyle(wrapper || h || card);
      return firstSurfaceValue([
        styles.getPropertyValue("--ddc-card-local-bg"),
        styles.getPropertyValue("--ddc-card-inner-bg"),
        styles.getPropertyValue("--ha-card-background"),
        styles.getPropertyValue("--card-background-color"),
        styles.getPropertyValue("--paper-card-background-color"),
        styles.getPropertyValue("--ddc-card-bg"),
        styles.backgroundImage,
        styles.backgroundColor
      ]);
    } catch (e) {}

    return "";
  }

  function keepWrapperTransparent(wrapper) {
    if (!wrapper) return;

    try {
      const props = [
        "--ddc-card-local-bg",
        "--ddc-card-inner-bg",
        "--ha-card-background",
        "--card-background-color",
        "--paper-card-background-color"
      ];

      props.forEach((prop) => {
        if (wrapper.style.getPropertyValue?.(prop) !== "transparent") {
          wrapper.style.setProperty(prop, "transparent");
        }
      });

      if (wrapper.style.background !== "transparent") wrapper.style.background = "transparent";
    } catch (e) {}
  }

  function syncDesignSurface() {
    const wrapper = getCardWrapper();
    const surface = readDesignSurface();
    const signature = surface || "default";

    if (signature !== lastDesignSurface) {
      lastDesignSurface = signature;

      if (surface) card.style.setProperty("--nb-design-bg", surface);
      else card.style.removeProperty("--nb-design-bg");
    }

    keepWrapperTransparent(wrapper);
  }

  function observeDesignSource() {
    const wrapper = getCardWrapper();
    if (!wrapper || typeof MutationObserver === "undefined") {
      syncDesignSurface();
      return;
    }

    try { card.__neoBatterySurfaceObserver?.disconnect?.(); } catch (e) {}

    try {
      card.__neoBatterySurfaceObserver = new MutationObserver(() => syncDesignSurface());
      card.__neoBatterySurfaceObserver.observe(wrapper, {
        attributes: true,
        attributeFilter: ["style", "class", "data-card-style"]
      });
    } catch (e) {}

    syncDesignSurface();
  }

  function states() {
    return Object.values((liveHass && liveHass.states) || {});
  }

  function getHidden() {
    try {
      return JSON.parse(localStorage.getItem(CONFIG.storage_key) || "[]");
    } catch (e) {
      return [];
    }
  }

  function setHidden(list) {
    localStorage.setItem(CONFIG.storage_key, JSON.stringify([...new Set(list)]));
  }

  function hideEntity(entityId) {
    const hidden = getHidden();
    hidden.push(entityId);
    setHidden(hidden);
    render(true);
  }

  function resetHidden() {
    setHidden([]);
    render(true);
  }

  function num(value) {
    const n = Number(value);
    return Number.isFinite(n) ? n : null;
  }

  function escapeHtml(value) {
    return String(value ?? "").replace(/[&<>"']/g, (ch) => ({
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;"
    }[ch]));
  }

  function iconFor(entity, name) {
    const id = String(entity.entity_id || "").toLowerCase();
    const n = String(name || "").toLowerCase();

    if (id.includes("tesla") || n.includes("tesla") || n.includes("car")) return "mdi:car-electric";
    if (n.includes("watch")) return "mdi:watch";
    if (n.includes("airpod") || n.includes("headphone")) return "mdi:headphones";
    if (n.includes("ipad") || n.includes("tablet")) return "mdi:tablet";
    if (n.includes("phone") || n.includes("iphone")) return "mdi:cellphone";
    if (n.includes("doorbell") || n.includes("ring")) return "mdi:doorbell-video";
    if (n.includes("vacuum") || n.includes("roborock")) return "mdi:robot-vacuum";
    if (n.includes("dyson")) return "mdi:vacuum";
    if (n.includes("remote")) return "mdi:remote";
    if (n.includes("sensor")) return "mdi:access-point";
    return "mdi:battery";
  }

  function areaGuess(entity) {
    const area =
      entity.attributes?.area ||
      entity.attributes?.room ||
      entity.attributes?.location;

    if (area) return area;

    const name = entity.attributes?.friendly_name || entity.entity_id || "";
    const clean = String(name)
      .replace(/ battery level| battery| batteri| nivå| level| percentage| percent/gi, "")
      .replace(/_/g, " ")
      .trim();

    const parts = clean.split(/\s+/);
    return parts.length > 1 ? parts.slice(0, -1).join(" ") : "Home";
  }

  function looksLikeBattery(entity) {
    if (!entity.entity_id) return false;

    const value = num(entity.state);
    if (value === null || value < 0 || value > 100) return false;

    const id = String(entity.entity_id || "").toLowerCase();
    const name = String(entity.attributes?.friendly_name || "").toLowerCase();
    const unit = String(entity.attributes?.unit_of_measurement || "").toLowerCase();
    const cls = String(entity.attributes?.device_class || "").toLowerCase();
    const icon = String(entity.attributes?.icon || "").toLowerCase();

    if (cls === "battery") return true;
    if (icon.includes("battery")) return true;

    const hasBatteryName =
      id.includes("battery") ||
      id.includes("batteri") ||
      id.includes("batt") ||
      name.includes("battery") ||
      name.includes("batteri") ||
      name.includes("batt");

    if (hasBatteryName && (unit === "%" || id.startsWith("sensor."))) return true;

    return false;
  }

  function batteryEntities() {
    const hidden = getHidden();

    return states()
      .filter((entity) => !hidden.includes(entity.entity_id))
      .filter(looksLikeBattery)
      .map((entity) => {
        const value = Math.round(num(entity.state) || 0);

        const rawName = entity.attributes?.friendly_name || entity.entity_id;

        const name = String(rawName)
          .replace(/ battery level| battery| batteri| nivå| level| percentage| percent/gi, "")
          .replace(/^sensor\./, "")
          .replace(/_/g, " ")
          .trim();

        const charging =
          entity.attributes?.is_charging === true ||
          entity.attributes?.charging === true ||
          String(entity.attributes?.battery_charging || "").toLowerCase() === "true" ||
          String(entity.attributes?.status || "").toLowerCase().includes("charg") ||
          String(entity.attributes?.power_source || "").toLowerCase().includes("usb");

        const status =
          charging ? "Charging" :
          value <= 20 ? "Low" :
          value <= 45 ? "Standby" :
          "Active";

        const stateColor =
          charging ? "var(--green)" :
          value <= 20 ? "var(--red)" :
          value <= 45 ? "var(--orange)" :
          "var(--cyan)";

        const barColor =
          value <= 20 ? "var(--red)" :
          value <= 45 ? "var(--orange)" :
          "var(--green)";

        return {
          id: entity.entity_id,
          name,
          area: areaGuess(entity),
          value,
          status,
          stateColor,
          barColor,
          icon: iconFor(entity, name)
        };
      })
      .sort((a, b) => a.value - b.value);
  }

  function filteredBatteries() {
    const all = batteryEntities();

    if (filterMode === "low") return all.filter((b) => b.value <= 25);
    if (filterMode === "charging") return all.filter((b) => b.status === "Charging");
    if (filterMode === "standby") return all.filter((b) => b.status === "Standby");

    return all;
  }

  function filterLabel() {
    if (filterMode === "low") return "Low battery";
    if (filterMode === "charging") return "Charging";
    if (filterMode === "standby") return "Standby";
    return "All devices";
  }

  function nextFilter() {
    const modes = ["all", "low", "charging", "standby"];
    const index = modes.indexOf(filterMode);
    filterMode = modes[(index + 1) % modes.length];
    localStorage.setItem("neo_batteries_filter_v1", filterMode);
    render(true);
  }

  function render(force) {
    syncDesignSurface();
    liveHass = (typeof hass !== "undefined") ? hass : window.hass || liveHass;

    const allVisible = batteryEntities();
    const batteries = filteredBatteries();
    const hiddenCount = getHidden().length;

    if (!allVisible.length && !hiddenCount) {
      card.innerHTML = `<div class="nb-empty">No battery devices found</div>`;
      return;
    }

    const shown = batteries.slice(0, CONFIG.max_items);
    const avg = allVisible.length
      ? Math.round(allVisible.reduce((sum, b) => sum + b.value, 0) / allVisible.length)
      : 0;

    const charging = allVisible.filter((b) => b.status === "Charging").length;
    const low = allVisible.filter((b) => b.value <= 20).length;
    const lowest = allVisible[0];

    card.innerHTML = `
      <div class="nb-shell">
        <header class="nb-top">
          <div class="nb-title">
            <div class="nb-main-icon">
              <ha-icon icon="mdi:battery-charging-high"></ha-icon>
            </div>

            <div>
              <h2>Batteries</h2>
              <p>All battery-powered devices in your home</p>
            </div>
          </div>

          <div class="nb-actions">
            <button class="nb-filter" data-action="filter">
              <span>${escapeHtml(filterLabel())}</span>
              <ha-icon icon="mdi:chevron-down"></ha-icon>
            </button>

            <button class="nb-round" data-action="reset-hidden" title="Show hidden devices">
              <ha-icon icon="mdi:eye-refresh-outline"></ha-icon>
            </button>
          </div>
        </header>

        <main class="nb-content">
          <section class="nb-list-card">
            <div class="nb-list">
              ${
                shown.length
                  ? shown.map((b, index) => `
                    <div class="nb-row">
                      <div class="nb-index">${index + 1}</div>

                      <div class="nb-device-icon">
                        <ha-icon icon="${b.icon}"></ha-icon>
                      </div>

                      <div class="nb-info">
                        <strong>${escapeHtml(b.name)}</strong>
                        <span>${escapeHtml(b.area)}</span>
                      </div>

                      <div class="nb-bar">
                        <i style="--level:${b.value}%; --bar-color:${b.barColor};"></i>
                      </div>

                      <div class="nb-percent">${b.value}%</div>

                      <div class="nb-state" style="--state-color:${b.stateColor}; color:${b.stateColor};">
                        <i></i>${escapeHtml(b.status)}
                      </div>

                      <button class="nb-row-action" data-action="hide" data-entity="${escapeHtml(b.id)}" title="Hide device">
                        <ha-icon icon="mdi:eye-off-outline"></ha-icon>
                      </button>
                    </div>
                  `).join("")
                  : `<div class="nb-empty">No devices in this filter</div>`
              }
            </div>

            <div class="nb-footer">
              <span>${batteries.length} shown · ${allVisible.length} visible · ${hiddenCount} hidden</span>
              ${hiddenCount ? `<button data-action="reset-hidden">Show hidden</button>` : ""}
            </div>
          </section>

          <aside class="nb-summary-card">
            <div class="nb-charge">
              <div class="nb-ring" style="--avg:${avg}%;">
                <div class="nb-ring-content">
                  <ha-icon icon="mdi:battery-charging-high"></ha-icon>
                  <div class="nb-ring-label">Total Charge</div>
                  <div class="nb-ring-value">${avg}%</div>
                </div>
              </div>
              <div class="nb-ring-caption">Across visible devices</div>
            </div>

            <div class="nb-insights">
              <div class="nb-section-title">Insights</div>

              <div class="nb-insight">
                <div class="nb-insight-icon">
                  <ha-icon icon="mdi:flash"></ha-icon>
                </div>
                <div>
                  <strong>${charging} devices charging</strong>
                  <span>Currently receiving power</span>
                </div>
              </div>

              <div class="nb-insight">
                <div class="nb-insight-icon">
                  <ha-icon icon="mdi:battery-alert"></ha-icon>
                </div>
                <div>
                  <strong>${low} low batteries</strong>
                  <span>${low ? "Needs attention soon" : "Everything looks good"}</span>
                </div>
              </div>

              <div class="nb-insight">
                <div class="nb-insight-icon">
                  <ha-icon icon="mdi:clock-outline"></ha-icon>
                </div>
                <div>
                  <strong>Lowest remaining</strong>
                  <span>${lowest ? `${escapeHtml(lowest.name)} · ${lowest.value}%` : "--"}</span>
                </div>
              </div>
            </div>

            <div class="nb-settings" data-action="filter">
              <ha-icon icon="mdi:tune-variant"></ha-icon>
              <span>Change filter</span>
              <ha-icon icon="mdi:chevron-right"></ha-icon>
            </div>
          </aside>
        </main>
      </div>
    `;
  }

  card.addEventListener("click", function (event) {
    const target = event.target.closest("[data-action]");
    if (!target || !card.contains(target)) return;

    const action = target.dataset.action;

    if (action === "filter") {
      nextFilter();
      return;
    }

    if (action === "hide") {
      const entityId = target.dataset.entity;
      if (entityId) hideEntity(entityId);
      return;
    }

    if (action === "reset-hidden") {
      resetHidden();
      return;
    }
  });

  observeDesignSource();
  render(true);

  clearInterval(card.__neoBatteryTimer);
  card.__neoBatteryTimer = setInterval(() => render(false), 15000);
})();
